var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一件重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"經過長久的思考，你明白在今後即將面對的命運中，她是不可缺少的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你下定決心。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called her to your office. She said she'd be here soon.","TWN":"做好心理準備後，你將她傳喚到老闆辦公室，她說馬上就會過來。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"친구 사이에 계약이 어딨어.","JPN":"友達同士で契約なんかしないでしょ。","ENG":"There are no such things as contracts between friends.","TWN":"朋友之間哪需要簽什麼約！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"그런 거 안 해도 되는데?","JPN":"そんなことしなくていいんだけど？","ENG":"You don’t need to do that.","TWN":"不需要吧？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"뭐든 말만 해. 다 들어줄 테니까.","JPN":"なんでも言って。なんだって聞いてやるから。","ENG":"Just say it, and I’ll make it happen.","TWN":"有什麼事就儘管直說，我都會照辦！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"……그런 계약이 아니라고? 그럼?","JPN":"……そんな契約じゃないって？　じゃあ、なに？","ENG":"...It’s not that kind of contract? Then what is it?","TWN":"……你想簽的不是這種契約？那是什麼？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"난 아직 계약 같은 걸 해 본 적이 없어서……","JPN":"私はまだ契約とかしたことがないから……","ENG":"I haven’t made any contracts before...","TWN":"我還沒有跟人家簽約的經驗……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"뭘 어떻게 하는 건데?","JPN":"何をどうすればいい？","ENG":" How is this supposed to be done?","TWN":"不太明白要怎麼做。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"으음. 그러니까…….","JPN":"うーん。だから……","ENG":"Umm. So...","TWN":"嗯，你的意思是……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"서로 소원 들어주기…… 라고 생각하면 되나?","JPN":"お互いの願い事を叶えてあげる……って思えばいいの？","ENG":"I can think of it as... we fulfill each other’s wishes?","TWN":"就當作……聽彼此的願望？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"뭐야. 진작 그렇게 얘기하지.","JPN":"なんだ、最初からそう言ってよ。","ENG":"Huh. You should’ve said that from the start.","TWN":"什麼嘛～你早說嘛～"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"……내 소원이라.","JPN":"……私の願いか。","ENG":"My wish...?","TWN":"……我的願望嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"예전엔 더 빨리 달리고 싶었어. 더 빨라지면 더 더 빨라지고 싶었고.","JPN":"昔はもっと速く走りたかった。それで速くなったら、それよりももっと速くなりたかった。","ENG":"I used to want to run faster. But once I got faster, I just wanted to become even more faster.","TWN":"我以前的願望是想要跑得更快，跑得更快後再更快！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"하지만 지금은……","JPN":"でも今は……","ENG":"But now...","TWN":"不過現在……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"……역시 말 안 할래.","JPN":"……やっぱり言うのはやめとく。","ENG":"...Yeah, I don’t want to say it.","TWN":"……不說了。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"이미 이뤄 진 걸 다시 바랄 필요는 없으니까.","JPN":"すでに叶えたことを、もう一度願う必要はないから。","ENG":"No need to wish for something that’s already been fulfilled again.","TWN":"反正願望都已經實現了，就不需要再許願了。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"대신 네 소원은 내가 빌어 줄게.","JPN":"代わりにあんたの願い事を祈ってあげる。","ENG":"But, I’ll make your wish for you.","TWN":"但我可以替你許願！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"이래 봬도 소원 들어주는 마법 구두를 가지고 있거든.","JPN":"こう見えても、願いを叶えてくれる魔法の靴を持ってるんだ。","ENG":"You see, I have magical slippers that make wishes come true.","TWN":"你不要看我這樣喔，我可是有一雙可以幫你實現願望的魔法鞋呢！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"구두를 딱, 딱, 딱 세 번 부딪치고, 소원을 빌면 돼.","JPN":"かかとを3回鳴らして、願い事をすればいい。","ENG":"I just need to *tap*, *tap*, *tap* tap my slippers three times and then make a wish.","TWN":"只要像這樣，咚咚咚，敲鞋子三下，就可以許願囉！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"자. 네 소원이 뭔데?","JPN":"さあ、あんたの願いは何？","ENG":"So, what’s your wish?","TWN":"說吧，你的願望是什麼？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}}]`);export{e as default};